import{_ as a,o as s,c as i,S as r}from"./chunks/framework.DZlzLDBr.js";const u=JSON.parse('{"title":"Basic & Reversed Cards","description":"","frontmatter":{},"headers":[],"relativePath":"Basic-&-Reversed-Cards.md","filePath":"Basic-&-Reversed-Cards.md","lastUpdated":null}'),o={name:"Basic-&-Reversed-Cards.md"};function t(d,e,n,l,c,h){return s(),i("div",null,[...e[0]||(e[0]=[r(`<h1 id="basic-reversed-cards" tabindex="-1">Basic &amp; Reversed Cards <a class="header-anchor" href="#basic-reversed-cards" aria-label="Permalink to &quot;Basic &amp; Reversed Cards&quot;">​</a></h1><p>Last modified: 13/02/2026</p><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Basic cards show a question first, then an answer. Reversed cards add a second card automatically so you study both directions.</p><h2 id="basic-card-format" tabindex="-1">Basic card format <a class="header-anchor" href="#basic-card-format" aria-label="Permalink to &quot;Basic card format&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>T | Title |</span></span>
<span class="line"><span>Q | What is the capital of France? |</span></span>
<span class="line"><span>A | Paris |</span></span>
<span class="line"><span>I | Extra context |</span></span>
<span class="line"><span>G | Geography |</span></span></code></pre></div><ul><li>Required fields: <code>Q</code> and <code>A</code></li><li>Optional fields: <code>T</code>, <code>I</code>, <code>G</code></li></ul><h2 id="create-with-the-modal" tabindex="-1">Create with the modal <a class="header-anchor" href="#create-with-the-modal" aria-label="Permalink to &quot;Create with the modal&quot;">​</a></h2><ol><li>Right-click in a note.</li><li>Choose <strong>Add flashcard → Basic Card</strong>.</li><li>Fill in fields and save.</li></ol><h2 id="reversed-behavior" tabindex="-1">Reversed behavior <a class="header-anchor" href="#reversed-behavior" aria-label="Permalink to &quot;Reversed behavior&quot;">​</a></h2><p>With reverse enabled, Sprout creates:</p><ol><li>Question → Answer</li><li>Answer → Question</li></ol><p>Use the reverse option in the modal to enable this.</p><h2 id="grading" tabindex="-1">Grading <a class="header-anchor" href="#grading" aria-label="Permalink to &quot;Grading&quot;">​</a></h2><p>After revealing the answer, grade your recall:</p><ul><li>two-button mode: Again / Good</li><li>four-button mode: Again / Hard / Good / Easy</li></ul><p>See <a href="./Grading">Grading</a>.</p><h2 id="edge-cases-and-tips" tabindex="-1">Edge cases and tips <a class="header-anchor" href="#edge-cases-and-tips" aria-label="Permalink to &quot;Edge cases and tips&quot;">​</a></h2><ul><li>If <code>Q</code> or <code>A</code> is missing, the card cannot work correctly.</li><li>Keep one fact per card for better retention.</li><li>Use <code>I</code> for hints or references instead of making <code>A</code> too long.</li><li>Use groups to organize by topic.</li></ul>`,19)])])}const v=a(o,[["render",t]]);export{u as __pageData,v as default};
